// ───────────────────────────────────────────────────────────────
// MODULE: Tree-Sitter WASM Parser
// ───────────────────────────────────────────────────────────────
// Implements ParserAdapter using web-tree-sitter with prebuilt
// WASM grammars. Cursor-based AST walk extracts RawCapture[]
// compatible with capturesToNodes()/extractEdges() from
// structural-indexer.ts.

import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createRequire } from 'node:module';
import type {
  ParseResult, SupportedLanguage, SymbolKind, EdgeType,
} from './indexer-types.js';
import { generateContentHash } from './indexer-types.js';
import { detectorProvenanceFromParserBackend } from './structural-indexer.js';
import {
  extractEdges,
  capturesToNodes,
  rememberParseResultCaptures,
  type RawCapture,
} from './structural-indexer.js';
import { isSpeckitMetricsEnabled, speckitMetrics } from './shared/metrics-stub.js';
import { addToSkipList, lookupSkipList, type SkipListEntry } from './parser-skip-list.js';

// ── Types ──────────────────────────────────────────────────────
// RawCapture is imported from structural-indexer.ts (single source of truth)

/** ParserAdapter interface — mirrors structural-indexer.ts:16-18 */
interface ParserAdapter {
  parse(
    content: string,
    language: SupportedLanguage,
    edgeWeights?: Partial<Record<EdgeType, number>>,
    filePath?: string,
  ): ParseResult;
}

// ── Lazy initialization state ──────────────────────────────────

// eslint-disable-next-line @typescript-eslint/no-explicit-any
let ParserClass: any = null;
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let parserInstance: any = null;
let initPromise: Promise<void> | null = null;
let parserHealth: 'ok' | 'quarantined' = 'ok';

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const grammarCache = new Map<SupportedLanguage, any>();
type ParserLanguage = Exclude<SupportedLanguage, 'doc'>;
const SUPPORTED_LANGUAGES: ParserLanguage[] = ['javascript', 'typescript', 'python', 'bash'];
const SKIP_LIST_ENABLED = process.env.SPECKIT_PARSER_SKIP_LIST_ENABLED !== 'false';

const __dirname = dirname(fileURLToPath(import.meta.url));
const localRequire = createRequire(import.meta.url);

export function getParserHealth(): 'ok' | 'quarantined' {
  return parserHealth;
}

/**
 * Test-only reset for the module-level parserHealth singleton.
 * Production code clears quarantine via MCP server restart only. The double-
 * underscore prefix signals internal/test scope. Vitest cases that exercise
 * the quarantine path call this in afterEach so the singleton does not leak
 * across `it()` blocks within the same module instance.
 */
export function __resetParserHealth(): void {
  parserHealth = 'ok';
}

/**
 * Production recovery from a global parser quarantine.
 *
 * A B2 fault ("memory access out of bounds") quarantines the parser for the
 * remainder of the process to avoid compounding WASM-heap corruption. Before
 * this function the only escape was a launcher restart, so a single B2 stranded
 * every subsequent scan (full scans returned zero nodes, which the scan
 * handler's zero-node guard then rejected to protect the existing graph).
 *
 * An explicit full scan is a deliberate "retry" signal, so the scan handler
 * calls this to clear the quarantine AND drop the parser instance + grammar
 * cache. The next parse re-runs `ensureInit()`, rebuilding a fresh
 * web-tree-sitter instance on a clean heap rather than reusing the corrupted
 * one. Distinct from `__resetParserHealth` (test-only flag flip that leaves the
 * instance in place).
 */
export function resetParserHealth(): void {
  parserHealth = 'ok';
  parserInstance = null;
  initPromise = null;
  grammarCache.clear();
}

export function classifyError(err: unknown): 'B1' | 'B2' | 'OTHER' {
  const message = err instanceof Error ? err.message : String(err);
  if (message.includes('resolved is not a function')) return 'B1';
  if (message.includes('memory access out of bounds')) return 'B2';
  return 'OTHER';
}

function earlyReturnSentinel(
  content: string,
  language: SupportedLanguage,
  startTime: number,
  reason: 'skip-list' | 'quarantined',
  skipEntry: SkipListEntry | null,
): ParseResult {
  const detail = reason === 'skip-list' && skipEntry
    ? `Parser skipped by skip-list (${skipEntry.errorClass}): ${skipEntry.errorMessage ?? 'no message'}`
    : 'Tree-sitter parser quarantined after memory access out of bounds';
  return {
    filePath: skipEntry?.filePath ?? '',
    language,
    nodes: [],
    edges: [],
    detectorProvenance: detectorProvenanceFromParserBackend('treesitter'),
    contentHash: generateContentHash(content),
    parseHealth: 'error',
    parseErrors: [detail],
    parseDurationMs: Date.now() - startTime,
  };
}

// Resolve grammar path via the tree-sitter-wasms package
// itself (Node module resolution) rather than a relative `../../` walk.
// Pre-fix used `resolve(__dirname, '../../node_modules/tree-sitter-wasms/out', ...)`
// which works when running from src (`mcp_server/lib/`) but fails from compiled
// `dist/lib/` because dist/ has no node_modules child. The previous
// path silently failed, web-tree-sitter init threw ENOENT, and the parser
// degraded to a regex fallback that extracts only the first ~3 callable nodes
// per file — leaving 60-80% of production symbols missing from `code_nodes`.
function getGrammarPath(language: ParserLanguage): string {
  const nameMap: Record<ParserLanguage, string> = {
    javascript: 'tree-sitter-javascript',
    typescript: 'tree-sitter-typescript',
    python: 'tree-sitter-python',
    bash: 'tree-sitter-bash',
  };
  try {
    const pkgJson = localRequire.resolve('tree-sitter-wasms/package.json');
    return resolve(dirname(pkgJson), 'out', `${nameMap[language]}.wasm`);
  } catch {
    // Fallback: try the legacy relative path (for any environment that
    // ships node_modules alongside dist/, e.g. some bundlers).
    return resolve(__dirname, '../../node_modules/tree-sitter-wasms/out', `${nameMap[language]}.wasm`);
  }
}

async function ensureInit(): Promise<void> {
  if (parserInstance) return;
  if (initPromise) return initPromise;

  initPromise = (async () => {
    try {
      const mod = await import('web-tree-sitter');
      ParserClass = mod.default ?? mod;
      await ParserClass.init();
      parserInstance = new ParserClass();
    } catch (err) {
      // Reset so the next call retries instead of being stuck with a rejected promise
      initPromise = null;
      parserInstance = null;
      throw err;
    }
  })();

  return initPromise;
}

async function getLanguageGrammar(language: ParserLanguage): Promise<unknown> {
  const cached = grammarCache.get(language);
  if (cached) return cached;

  await ensureInit();

  const grammarPath = getGrammarPath(language);
  const lang = await ParserClass.Language.load(grammarPath);
  grammarCache.set(language, lang);
  return lang;
}

// ── Node type → SymbolKind mapping ─────────────────────────────

const JS_TS_KIND_MAP: Record<string, SymbolKind> = {
  function_declaration: 'function',
  generator_function_declaration: 'function',
  method_definition: 'method',
  abstract_method_signature: 'method',
  class_declaration: 'class',
  abstract_class_declaration: 'class',
  interface_declaration: 'interface',
  type_alias_declaration: 'type_alias',
  enum_declaration: 'enum',
  import_statement: 'import',
  import_declaration: 'import',
  export_statement: 'export',
  export_declaration: 'export',
};

const PYTHON_KIND_MAP: Record<string, SymbolKind> = {
  function_definition: 'function',
  class_definition: 'class',
  import_statement: 'import',
  import_from_statement: 'import',
};

const BASH_KIND_MAP: Record<string, SymbolKind> = {
  function_definition: 'function',
};

function getKindMap(language: SupportedLanguage): Record<string, SymbolKind> {
  switch (language) {
    case 'javascript':
    case 'typescript':
      return JS_TS_KIND_MAP;
    case 'python':
      return PYTHON_KIND_MAP;
    case 'bash':
      return BASH_KIND_MAP;

