}

export interface EnsureReadyOptions {
  allowInlineIndex?: boolean;
  allowInlineFullScan?: boolean;
  allowGuardedInlineFullScan?: boolean;
  parseErrorBacklogThreshold?: number;
}

// ───────────────────────────────────────────────────────────────
// Constants
